INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('ca0c8d1b-8cec-4413-a2db-a378268d9b20', E'教学目标篇', E'深入了解并掌握布卢姆教育目标分类学的基本理论框架，包括其核心的认知维度层次划分（如记忆、理解、应用、分析、评价和创造等）以及各层次之间的内在逻辑关系，同时全面学习该分类学在实际教育教学场景中的具体应用方法与策略，例如如何依据不同的教育目标层次设计课程教学内容、制定教学计划、开发教学评估工具以及指导学生的学习活动等。', 1, '2025-12-30T08:15:04.279327+00:00', '2026-04-22T07:26:24.357276+00:00', true, ARRAY["open-class", "daily-class"]::"text"[], ARRAY["一线老师", "创新教育老师"]::"text"[], ARRAY["公开课", "日常课"]::"text"[], ARRAY["备课核心要素"]::"text"[]);
