INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('bd2be44e-5710-44d4-9af8-2178db010d0e', E'学情分析篇', NULL, 2, '2026-04-10T06:25:13.111279+00:00', '2026-04-22T07:26:53.285734+00:00', true, ARRAY["open-class", "daily-class"]::"text"[], ARRAY["一线老师", "创新教育老师"]::"text"[], ARRAY["公开课", "日常课"]::"text"[], ARRAY["备课核心要素"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('20b46fd9-b1a6-4d2b-8b6c-bab8f56ba8c2', E'任务情境篇', E'在人工智能技术迅猛发展、深刻重塑社会各领域的时代背景下，教育作为培养未来人才的核心领域正面临着前所未有的变革挑战与发展机遇。传统以知识传授为核心、以教师为中心的教育模式，在海量信息唾手可得、智能工具辅助学习日益普及的今天，其局限性愈发凸显，因此教育体系亟需进行系统性重构。在这一变革进程中，任务导向教学凭借其独特的优势，展现出至关重要的价值与意义。这种教学模式强调以真实、复杂且具有挑战性的任务为核心驱动力，引导学生在主动探究、协作解决问题的过程中，不仅能够深入理解和灵活运用知识，更能有效培养批判性思维、创新能力、沟通协作能力以及自主学习能力等面向未来社会的关键素养，从而更好地适应人工智能时代对人才提出的全新要求。', 3, '2025-12-30T08:15:04.279327+00:00', '2026-04-30T02:22:08.456175+00:00', true, ARRAY["open-class"]::"text"[], ARRAY["一线老师", "创新教育老师"]::"text"[], ARRAY["公开课", "日常课"]::"text"[], ARRAY["备课核心要素"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('beef29de-ff51-4a95-8864-6c8c7ee6bd51', E'AI科普', NULL, 3, '2026-03-17T12:32:10.063922+00:00', '2026-04-10T11:35:21.564144+00:00', true, '{}'::"text"[], ARRAY["先锋老师"]::"text"[], '{}'::"text"[], ARRAY["知识科普"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('27fe7dd9-ea7f-4c2f-890d-4fd24d4c0a3f', E'教学评价篇', NULL, 4, '2026-04-22T07:25:11.492097+00:00', '2026-04-22T07:32:24.543359+00:00', true, '{}'::"text"[], ARRAY["一线老师", "创新教育老师"]::"text"[], ARRAY["公开课"]::"text"[], ARRAY["备课核心要素"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('5ee730ec-deec-4efd-b9c9-95331a48fd20', E'概念教学篇', NULL, 5, '2026-01-17T13:47:53.767909+00:00', '2026-04-30T02:22:30.899897+00:00', true, '{}'::"text"[], ARRAY["一线老师", "创新教育老师"]::"text"[], ARRAY["日常课"]::"text"[], '{}'::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('59133228-2d33-432c-9db0-82da2469a8c5', E'讲授法篇', E'在当今教育教学改革不断深化的背景下，我们有必要以全新的视角重新审视传统讲授法这一长期以来广泛应用于各级各类教育领域的教学模式，深入探究并全面理解其在现代化教学环境中所具有的独特价值以及不可忽视的局限性。传统讲授法作为一种历史悠久的教学方法，凭借其能够在相对较短的时间内系统、高效地向学生传递大量知识信息，帮助学生构建起完整的知识框架和理论体系，在知识传授的效率方面展现出显著优势，尤其适用于基础概念、理论原理等系统性知识的教学环节。然而，在强调学生主体性、注重培养学生创新思维和实践能力的现代教育理念下，传统讲授法也暴露出一定的局限性，例如在教学过程中往往更多地体现为教师单向的知识输出，容易忽视学生的个体差异和主动参与，可能在一定程度上限制学生批判性思维和自主学习能力的充分发展。因此，只有全面、客观地认识传统讲授法的双重属性，才能在实际教学实践中做到扬长避短，实现与其他教学方法的有机结合与优势互补，从而更好地适应现代教育发展的需求，提升教学质量和育人效果。', 6, '2025-12-30T08:15:04.279327+00:00', '2026-04-30T02:22:33.893687+00:00', true, ARRAY["daily-class"]::"text"[], ARRAY["一线老师"]::"text"[], ARRAY["日常课"]::"text"[], ARRAY["教学法"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('3cd9317a-7acd-4593-8bb7-1826259fb433', E'AI 通识课', E'AI 通识课', 7, '2026-03-07T03:27:57.58767+00:00', '2026-04-22T07:27:41.640318+00:00', true, ARRAY["open-class"]::"text"[], ARRAY["一线老师"]::"text"[], '{}'::"text"[], '{}'::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('764ef51a-eb9a-4703-8793-648eda5e2908', E'建构主义', E'学习如何以建构主义理论为核心指导思想，系统性地开展教学设计工作，包括深入理解学习者已有的知识经验基础，精心创设能够激发主动探究的学习情境，科学设计促进知识意义建构的互动环节与实践任务，以及合理运用多元化的教学评价方式来有效支持和引导学习者通过自主发现、协作交流完成对新知识的主动建构。', 8, '2025-12-30T08:15:04.279327+00:00', '2026-04-22T07:27:44.939492+00:00', true, '{}'::"text"[], ARRAY["一线老师", "创新教育老师", "家长"]::"text"[], ARRAY["公开课"]::"text"[], ARRAY["学习理论"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('a038b88a-bcb2-45fd-9dc5-a323b2b6e11b', E'学习科学篇', E'为了深入且系统地掌握学习科学这一跨学科领域的知识体系，我们需要全面了解其核心的基本概念，同时也要广泛涉猎该学科所涵盖的各个主要研究领域。这意味着不仅要清晰理解学习科学中那些基础性的定义、原理和理论框架，还要对其涉及的认知心理学、神经科学、教育学、计算机科学、社会学等多个相关学科的交叉研究范畴进行深入探究，从而构建起对学习科学的完整认知和全面把握。', 9, '2025-12-30T08:15:04.279327+00:00', '2026-04-30T02:22:19.54881+00:00', true, '{}'::"text"[], ARRAY["一线老师", "创新教育老师", "家长"]::"text"[], '{}'::"text"[], ARRAY["理论"]::"text"[]);
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('64bf16cb-33e5-4847-ba44-f2372617d669', E'认知负荷理论', E'要深入理解认知负荷理论，首先需要掌握其基本概念以及所包含的三种负荷类型。认知负荷理论是由澳大利亚心理学家约翰·斯威勒（John Sweller）等人提出的，该理论主要探讨人类在进行学习、问题解决等认知活动时，大脑工作记忆所承受的认知负担及其对学习效果和认知表现的影响。它认为，人的工作记忆容量是有限的，当认知负荷超过工作记忆的承载能力时，就会导致认知资源分配不足，进而影响学习效率和任务完成质量。
INSERT INTO "public"."course_categories" ("id", "name", "description", "sort_order", "created_at", "updated_at", "is_active", "scenarios", "applicable_audience", "applicable_scenarios", "content_types") VALUES ('ed3bcabc-307a-4a6c-83ef-71725de22223', E'罗森海因篇', E'为了切实提升教学成效与学生的学习质量，我们应当全面且深入地学习和领会罗森海因教学原理的核心内涵与实践方法。这意味着要系统梳理该原理所涵盖的各项关键教学策略，包括清晰明确的教学目标设定、结构化的知识呈现方式、及时有效的学习反馈机制、合理的教学进度安排以及充分的学习机会提供等多个重要方面。通过深入钻研这些内容，我们能够更好地把握教学过程中的内在规律，从而在实际教学情境中灵活运用相关策略，优化教学设计，激发学生的学习兴趣和主动性，最终促进学生知识的有效建构与能力的全面发展。', 11, '2025-12-30T08:15:04.279327+00:00', '2026-04-30T02:22:14.926651+00:00', true, ARRAY["daily-class"]::"text"[], ARRAY["一线老师", "创新教育老师", "家长"]::"text"[], ARRAY["日常课"]::"text"[], ARRAY["教学理论"]::"text"[]);
