INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('062f90f1-8543-41de-bad0-80fc33624598', E'拆解“得到”的教学设计', E'这节课的内容真的很扎实，它把“得到”这家成人教育互联网公司的底层逻辑拆解得非常透彻 。对于咱们老师来说，这不仅仅是一份案例拆解，更是一套实用的教学设计工具箱 。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('e342b2c8-6734-49f1-a16c-891b7cbf9c6f', E'给老师第一节教学通识课', E'这节课的精华在于哈老师耗时近一年、迭代了10个版本才磨出来的这张“AI时代的教学设计全景图” 。它不是简单的步骤说明，而是把教育哲学、教学科学、学习科学和系统论作为底层支柱，整合出的一个系统化框架 。全景图围绕真实任务设计、用户洞察、锚定目标、设计评价工具、设计学习旅程和研发教学包这六大核心模块，帮我们把零散的理论串成了一张网 。
