INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('00d04dfb-fbd0-48af-8d6a-b785fe87738a', E'01 | 为什么需要用户洞察？', E'哈老师阐述了用户洞察（学情分析）作为教学设计起点的核心地位，辨析了空泛与精准洞察的差异，并通过多学科案例论证了精准洞察对教学目标设定与教学策略选择的关键影响。', E'哈老师', 'bd2be44e-5710-44d4-9af8-2178db010d0e', E'学情分析篇', '入门', NULL, 10, 0.5, 'published', NULL, NULL, E'https://meeting.tencent.com/crm/K0YMrJxW2c', 1, 31, '2026-04-10T06:26:56.685218+00:00', '2026-05-08T06:26:34.964763+00:00', 'plus', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('b4ae2ac6-5594-45e3-a1c3-115953babd46', E'01 | 知识是被发现的，还是被发明的？建构主义的知识观', E'探讨知识的本质，理解建构主咱们平时上课，最怕的就是“我讲透了，学生却没听懂”。其实根源可能不在教学法，而在咱们对“知识”的理解。这节课想带大家跳出“教材就是绝对真理”的固有思维。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('110a1f3f-0839-4a44-a523-001e93a70f9d', E'01 | 初识布卢姆教育目标分类学框架', E'各位老师，咱们在备课时是不是常有这种纠结：心里想培养孩子很高大上的“计算思维”或“核心素养”，但一落实到具体的这节课（比如用Scratch画个雪花），又不知道该怎么写了？最后往往把“教学目标”写成了“教学活动”，或者写得很模糊，导致教到哪算哪。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('1b826283-c273-496e-ac8a-1f9fc1dae9e7', E'01 | 重新认识讲授法', E'提到“讲授法”，很多老师脑海里浮现的可能是枯燥的“填鸭”或者昏昏欲睡的课堂。但其实，讲授法被误解太久了。这节课，我们不谈大道理，而是从认知心理学的角度，重新审视这种最古老的教学法。
