INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d986c480-f6ae-4934-95e5-d9b010db3c41', E'03 | 评价方法1：逆向设计', E'本次培训由哈老师主讲，详细拆解了逆向设计（Backward Design）的三步法，重点阐述了如何通过具体化目标动词来锁定评价任务，并结合案例演示了从目标到评价再到活动的全流程逻辑。', E'哈老师', '27fe7dd9-ea7f-4c2f-890d-4fd24d4c0a3f', E'教学评价篇', '中级', NULL, 9, 0.5, 'published', NULL, NULL, E'https://meeting.tencent.com/crm/Ke4omjxz8c', 2, 7, '2026-04-22T07:38:05.906573+00:00', '2026-05-08T06:34:18.634726+00:00', 'plus', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d0a16d5e-5857-4768-a7d9-1d47638e8845', E'02 | 人是如何学习的？建构主义的学习观', E'很多老师觉得学生“固执”，错题改了还错。这节课我们要钻进学生的大脑，看看学习到底是怎么发生的。
