INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('192ef020-4f57-414e-be81-950a3cd48da0', E'02 | 如何设计一段60分钟的纯粹讲授？', E'这节课主要面向高校教师或成人培训师。面对心智成熟的学员，如何进行30到60分钟的长时间讲授，且让他们保持专注？秘诀不在于口才，而在于结构的设计。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('78c42429-944b-4fc4-aacf-9edd236bad04', E'04 | 评价方法2：提问互动', E'本次培训哈老师详细讲解了提问互动的评价方法，重点阐述了基于布鲁姆理论的递进式问题链设计策略，并针对学生答不出、答错及答对四种场景提供了具体的理答与评价反馈技巧。', E'哈老师', '27fe7dd9-ea7f-4c2f-890d-4fd24d4c0a3f', E'教学评价篇', '中级', NULL, 22, 1, 'published', NULL, NULL, E'https://meeting.tencent.com/crm/l6YadvQQ8d', 3, 5, '2026-04-22T07:39:42.215133+00:00', '2026-05-08T06:32:32.780951+00:00', 'plus', false);
