INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('3e50c9e0-bdcf-4824-80d5-e8c61bd01de5', E'03 | 如何设计一段互动讲授？', E'对于K12领域的老师来说，如何抓住孩子的注意力是永恒的难题。这节课我们聚焦“互动讲授”，它不是简单的“讲20分钟、练20分钟”，而是借鉴直导教学（Direct Instruction）的理念，强调“小步切块”。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('12540819-8c54-473d-861b-522d77d30f9c', E'03 | 讲授还是探究？建构主义的教学观', E'比较讲授式提到建构主义，大家可能会有误区，觉得必须得搞PBL、搞小组讨论才算。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('5188c255-9ae0-42b8-b62f-232becf190ad', E'03-如何给 ClaudeCode 配置大模型 API ？', E'本次培训哈老师详细演示了利用CC Switch与ofox平台实现 Claude Code多模型切换的实操流程，并解析了底层数据流转与协议转换原理，解决了高成本与低灵活性的痛点。', E'哈老师', '035b27f4-d302-4c60-b731-f90338d77ad7', E'ClaudeCode教程', '中级', NULL, 30, 0.5, 'published', E'https://images.unsplash.com/photo-1738107445976-9fbed007121f?q=80&w=2340&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', NULL, E'https://meeting.tencent.com/crm/2kYvMRxG8b', 3, 49, '2026-03-17T03:31:19.193659+00:00', '2026-05-14T02:40:16.073769+00:00', 'pro', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('1d2cea0c-0463-489f-997f-58873003a570', E'03 | 深入布卢姆的认知分类', E'我们常说要拒绝“填鸭式教学”，追求“有意义的学习”，但到底怎么才算“有意义”？在这一节课里，我们会深入探讨布卢姆分类中最核心的“认知过程”维度。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('c53119df-81c2-4f75-8e43-917ca5722e76', E'04 | 初识马扎诺➕SOLO分类理论', E'了解马扎诺和SOLO这节课，我们来点“新工具”。有时候我们觉得布卢姆太细了，不好评价学生到底学得怎么样，特别是面对作文、论述这种开放性问题时，很难打分。这时我们会引入“SOLO分类理论”，它就像一把尺子，能帮我们量出学生思维的“质量”，看他是只罗列了知识点，还是真的形成了逻辑结构。分类理论的基本概念。', E'哈老师', 'ca0c8d1b-8cec-4413-a2db-a378268d9b20', E'教学目标篇', '中级', NULL, 68, 1, 'published', E'https://images.unsplash.com/photo-1503676260728-1c00da094a0b?w=800', NULL, E'https://meeting.tencent.com/crm/Nbo0XG9D4f', 4, 13, '2025-12-30T08:04:59.943983+00:00', '2026-05-08T06:25:26.991021+00:00', 'plus', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('1fb4ce72-87fd-40a4-a8a5-2c94447078ff', E'05 | 评价方法3：评价量规', E'本次培训哈老师讲解了教学评价的三种层次，重点阐述了表现性评价中量规设计的三大核心要素，并通过《琥珀》自述案例演示了从维度划分到等级描述的完整设计流程。', E'哈老师', '27fe7dd9-ea7f-4c2f-890d-4fd24d4c0a3f', E'教学评价篇', '中级', NULL, 15, 0.5, 'published', NULL, NULL, E'https://meeting.tencent.com/crm/lR7AdaM19d', 4, 7, '2026-04-22T07:41:22.684349+00:00', '2026-05-08T06:32:53.190655+00:00', 'plus', false);
