INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d3c23599-b51f-4a3a-9753-3736a188106d', E'11-如何用AI挖深教材并产出一份几千字的教材挖深报告？', E'本次培训哈老师发布了“教材深挖”claudecode skill，旨在通过五维分析框架与苏格拉底式提问，辅助教师生成千字深度教材分析报告，以解决公开课同质化难题。', E'哈老师', '035b27f4-d302-4c60-b731-f90338d77ad7', E'ClaudeCode教程', '中级', NULL, 30, 0.5, 'published', E'https://images.unsplash.com/photo-1738107445976-9fbed007121f?q=80&w=2340&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', NULL, E'https://meeting.tencent.com/crm/23YvwaeJ0c', 11, 17, '2026-04-01T08:08:20.411473+00:00', '2026-05-10T13:58:19.231069+00:00', 'pro', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d64fb3b1-b1fa-47bb-b50c-8e099faead82', E'01 | AI时代为什么需要任务教学？', E'为什么你一定要看这节课： 很多老师最近可能都有种“技术焦虑”：AI 已经能写代码、做医学影像诊断，甚至在奥数竞赛中逼近金牌水平了。如果我们的课堂还在让学生背诵知识点、做那些只有单一标准答案的“模拟练习”，那我们其实是在培养最容易被 AI 替代的人。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('867435a8-bd3d-4c5e-91ae-b80531d86e89', E'02 | 深入理解任务', E'为什么你一定要看这节课： 我们常说“给学生布置个任务”，但你有没有发现，有时候我们布置的其实只是“活动”或是“练习”，而不是真正的“任务”。比如，带学生逛博物馆是活动，但让学生为博物馆设计一份导览手册，这就是任务。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('3e18d0ba-ec51-4325-8285-007e6d7b33a9', E'12-如何增强ClaudeCode的网络检索能力？', E'本次培训哈老师演示了通过安装 yt-search 和 notebook_py 两个 Skill 来增强 ClaudeCode 的 YouTube 视频搜索与 NotebokLM 自动导入能力，实现从搜索到生成高质量报告的全流程自动化。', E'哈老师', '035b27f4-d302-4c60-b731-f90338d77ad7', E'ClaudeCode教程', '中级', NULL, 10, 0.5, 'published', E'https://images.unsplash.com/photo-1738107445976-9fbed007121f?q=80&w=2340&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D', NULL, E'https://meeting.tencent.com/crm/2a5RMzbD41', 12, 13, '2026-03-23T07:33:31.914949+00:00', '2026-05-15T07:41:56.673372+00:00', 'pro', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('9baa912f-eac3-4c0f-8c01-ba35a08727e2', E'03 | KMR设计法：如何改造课后习题？', E'为什么你一定要看这节课： 听完前两课，你可能会觉得：“道理我都懂，但重新设计一节课太难了，教材里的内容怎么办？”这正是第三课要帮你解决的实操难题。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('c2e43817-7a67-4787-8aa0-aeb08258c3c5', E'04 | 任务脚本：如何从0到1原创任务？', E'为什么你一定要看这节课： 这是我们学习营的临门一脚，也是最能让你的设计产生“质感”的一课。很多老师设计任务时容易卡壳：想不出好点子，或者设计的身份太单一。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('59da5d19-7516-4049-b3db-9946669b6386', E'05 | 任务情境工具箱：5个任务公式设计好任务', E'本次培训哈老师针对任务设计实践痛点，构建了“类型选择+脚本具体化+动机赋能”的三步工具箱，并详细拆解了五大任务类型、五要素脚本及八大动机模型的应用逻辑。', E'哈老师', '20b46fd9-b1a6-4d2b-8b6c-bab8f56ba8c2', E'任务情境篇', '中级', NULL, 40, 1, 'published', E'https://images.unsplash.com/photo-1531482615713-2afd69097998?w=800', NULL, E'https://meeting.tencent.com/crm/2MWnorV624', 15, 6, '2026-04-17T03:15:52.170356+00:00', '2026-05-13T04:15:06.342861+00:00', 'plus', false);
