INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('c3e099a7-413f-4df2-82e7-1afdce507c86', E'07 | 单课任务驱动：任务串与子任务拆解', E'本次培训哈老师讲解了新课标下任务驱动教学的双线逻辑，传授了“确定核心情境+拆解子任务”的两步法，并通过语文与科学案例演示了任务串的递进式设计，最后提出了四项质检标准以确保任务链的有效性。', E'哈老师', '20b46fd9-b1a6-4d2b-8b6c-bab8f56ba8c2', E'任务情境篇', '中级', NULL, 12, 0.5, 'published', E'https://images.unsplash.com/photo-1531482615713-2afd69097998?w=800', NULL, E'https://meeting.tencent.com/crm/2j9V8aXn5c', 17, 10, '2026-04-17T04:01:48.685752+00:00', '2026-05-15T07:41:29.517491+00:00', 'plus', false);
