INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('f4341adf-4f9f-4776-b1cd-c1eb29b8f3c3', E'上下文窗口：喂5本PDF会爆吗？', E'本次培训哈老师详细解析了上下文窗口的定义与限制成因，演示了文档长度与模型容量的匹配计算方法，并系统介绍了RAG、摘要压缩等五种工程化优化策略。', E'哈老师', 'beef29de-ff51-4a95-8864-6c8c7ee6bd51', E'AI科普', '中级', NULL, 30, 0.5, 'published', E'https://images.unsplash.com/photo-1523191339508-68905a77d5e7?q=80&w=1674&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA==', NULL, E'https://meeting.tencent.com/crm/2G1OaPmA7b', 21, 22, '2026-03-09T12:40:40.102472+00:00', '2026-05-06T05:45:35.131303+00:00', 'pro', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('a00c3aa0-5dea-44e4-bc7a-23f47fa530d4', E'01 | 为什么你需要掌握概念教学？', E'本课是概念教学第一节，带大家走入概念的世界，分享为什么概念对培养学生学科认知如此重要。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d14ba59d-876e-47b5-bc43-1aa47034c2e7', E'02 | 重新理解概念', E'本课是概念教学第二节，我们讲讲“概念”这个概念到底啥意思，从认知心理学的角度重新理解概念。
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('d2a9cf19-b0ec-48fb-8a01-ed67448ec5a9', E'系统提示词：为什么Agent会拒绝回应某些请求？', E'本次培训哈老师通过案例演示了系统提示词的定义与拒绝机制，剖析了AI拒绝回答的三大边界及越狱风险，并详细阐述了设计安全且有用AI系统的四大原则。', E'哈老师', 'beef29de-ff51-4a95-8864-6c8c7ee6bd51', E'AI科普', '中级', NULL, 30, 0.5, 'published', E'https://plus.unsplash.com/premium_photo-1727558768347-eefa5276de9d?q=80&w=1770&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA==', NULL, E'https://meeting.tencent.com/crm/l5DyG3Ze18', 22, 10, '2026-03-09T12:41:24.001161+00:00', '2026-04-29T02:01:52.306366+00:00', 'pro', false);
INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('066c8182-11d5-4c9b-b010-207f02882c84', E'03 | 如何从教教材到教概念？', E'本课是概念教学的第三课。我们讲讲如何分析教材提取概念。教材里往往没有写清楚概念层级，那我们怎么办？
