INSERT INTO "public"."courses" ("id", "title", "description", "instructor", "category_id", "category", "level", "semester", "duration", "credits", "status", "image_url", "video_url", "meeting_url", "sort_order", "view_count", "created_at", "updated_at", "membership_type", "is_trial") VALUES ('979df791-4736-43dd-be80-45e305c465ff', E'20260227-AI主题直播答疑', E'这是一场关于AI技术在教育领域应用的讨论会。会议主要围绕教师如何利用AI工具进行教学备课、组卷命题以及知识库管理等话题展开交流。参会者探讨了国内外不同AI模型的优缺点，并分享了各自在实际教学中的使用经验和困惑。
